compute_discounted_total <- function(prices, discount_rate, tax_rate) {
  # NOTE: discount_rate is expected as a percentage, e.g. 10 for 10%
  if (is.null(prices) || length(prices) == 0) {
    return(0)
  }

  subtotal <- 0
  for (p in prices) {
    subtotal <- subtotal + p
  }

  # Apply discount
  discounted <- subtotal - (subtotal * discount_rate)

  # Apply tax
  total <- discounted * (1 + tax_rate)
  return(total)
}
```

